public class TrainConsistManagementApp {    public static boolean linearSearch(String[] bogieIds, String searchKey) {        for (String id : bogieIds) {            if (id.equals(searchKey)) {                return true;            }        }        return false;    }    public static void main(String[] args) {        String[] bogieIds = {"BG101","BG205","BG309","BG412","BG550"};        String searchKey1 = "BG309";        System.out.println("Searching for " + searchKey1 + ": " + linearSearch(bogieIds, searchKey1));        String searchKey2 = "BG999";        System.out.println("Searching for " + searchKey2 + ": " + linearSearch(bogieIds, searchKey2));        String searchKey3 = "BG101";        System.out.println("Searching for " + searchKey3 + ": " + linearSearch(bogieIds, searchKey3));        String searchKey4 = "BG550";        System.out.println("Searching for " + searchKey4 + ": " + linearSearch(bogieIds, searchKey4));        String[] singleArray = {"BG101"};        String searchKey5 = "BG101";        System.out.println("Searching in single-element array for " + searchKey5 + ": " + linearSearch(singleArray, searchKey5));    }}